export async function createProdHandler(project: ToolpadProject) {
  const handler = express.Router();

  handler.use(express.static(project.getAppOutputFolder(), { index: false }));

  // Allow static assets, block everything else
  handler.use((req, res, next) => {
    if (checkBasicAuthHeader(req.headers.authorization ?? null)) {
      next();
      return;
    }
    basicAuthUnauthorized(res);
  });

  const hasAuthentication = await getRequireAuthentication(project);
  if (hasAuthentication) {
    const authHandler = createAuthHandler(project);
    handler.use('/api/auth', express.urlencoded({ extended: true }), authHandler);

    handler.use(await createRequireAuthMiddleware(project));
  }

  handler.use('/api/data', project.dataManager.createDataHandler());

  const runtimeRpcServer = createRpcServer(project);
  handler.use('/api/runtime-rpc', createRpcHandler(runtimeRpcServer));

  handler.use(
    asyncHandler(async (req, res) => {
      const htmlFilePath = path.resolve(project.getAppOutputFolder(), './index.html');

      const [runtimeConfig, dom] = await Promise.all([
        project.getRuntimeConfig(),
        project.loadDom(),
      ]);

      let html = await fs.readFile(htmlFilePath, { encoding: 'utf-8' });

      html = postProcessHtml(html, {
        config: runtimeConfig,
        initialState: createRuntimeState({ dom }),
      });

      res.setHeader('Content-Type', 'text/html; charset=utf-8').status(200).end(html);
    }),
  );

  return { handler, dispose: async () => undefined };
}
type BasicAuthConfig =
  | {
      basicAuthUser: string;
      basicAuthPassword: string;
    }
  | {
      basicAuthUser?: undefined;
      basicAuthPassword?: undefined;
    };

export type ServerConfig = {
  databaseUrl?: string;
  googleSheetsClientId?: string;
  googleSheetsClientSecret?: string;
  encryptionKeys: string[];
  basicAuthUser?: string;
  basicAuthPassword?: string;
} & BasicAuthConfig;

function readConfig(): ServerConfig {
  if (typeof window !== 'undefined') {
    throw new Error(`Server-side config can't be loaded on the client side`);
  }

  // Whitespace separated, do not use spaces in your keys
  const encryptionKeys: string[] =
    process.env.TOOLPAD_ENCRYPTION_KEYS?.split(/\s+/).filter(Boolean) ?? [];

  let basicAuthConfig: BasicAuthConfig = {};
  if (process.env.TOOLPAD_BASIC_AUTH_USER && process.env.TOOLPAD_BASIC_AUTH_PASSWORD) {
    basicAuthConfig = {
      basicAuthUser: process.env.TOOLPAD_BASIC_AUTH_USER,
      basicAuthPassword: process.env.TOOLPAD_BASIC_AUTH_PASSWORD,
    };
  } else if (process.env.TOOLPAD_BASIC_AUTH_USER) {
    throw new Error(
      `Basic Auth user configured without password. Please provide the TOOLPAD_BASIC_AUTH_PASSWORD environment variable.`,
    );
  }

  return {
    ...basicAuthConfig,
    databaseUrl: process.env.TOOLPAD_DATABASE_URL,
    googleSheetsClientId: process.env.TOOLPAD_DATASOURCE_GOOGLESHEETS_CLIENT_ID,
    googleSheetsClientSecret: process.env.TOOLPAD_DATASOURCE_GOOGLESHEETS_CLIENT_SECRET,
    encryptionKeys,
  };
}

export default readConfig();
import type { IncomingMessage, ServerResponse } from 'http';
import config from './config';

export function checkBasicAuthHeader(headerContent: string | null): boolean {
  if (!config.basicAuthUser) {
    return true;
  }

  if (headerContent) {
    const auth = headerContent.split(' ')[1];
    const [user, pwd] = atob(auth).toString().split(':');

    if (user === config.basicAuthUser && pwd === config.basicAuthPassword) {
      return true;
    }
  }

  return false;
}

export function checkBasicAuth(req: IncomingMessage): boolean {
  return checkBasicAuthHeader(req.headers.authorization || null);
}

export function basicAuthUnauthorized(res: ServerResponse): void {
  res.setHeader('WWW-Authenticate', 'Basic realm="Protected"');
  res.statusCode = 401;
  res.end('Unauthorized');
}
import type { IncomingMessage, ServerResponse } from 'http';
import * as superjson from 'superjson';
import express from 'express';
import * as z from 'zod';
import { fromZodError } from 'zod-validation-error';
import { hasOwnProperty } from '@mui/toolpad-utils/collections';
import { errorFrom, serializeError } from '@mui/toolpad-utils/errors';
import { withContext, createServerContext } from '@mui/toolpad-core/serverRuntime';
import { asyncHandler } from '../utils/express';

export interface Method<P extends any[] = any[], R = any> {
  (...params: P): Promise<R>;
}

export interface Methods {
  readonly [key: string]: Method;
}

interface ResolverInput<P> {
  params: P;
  req: IncomingMessage;
  res: ServerResponse;
}

export interface MethodResolver<F extends Method> {
  (input: ResolverInput<Parameters<F>>): ReturnType<F>;
}

export interface MethodResolvers {
  readonly [key: string]: MethodResolver<any>;
}

export type MethodsOf<R extends MethodResolvers> = {
  [K in keyof R]: (...params: Parameters<R[K]>[0]['params']) => ReturnType<R[K]>;
};

const rpcRequestSchema = z.object({
  name: z.string(),
  params: z.array(z.any()),
});

export type RpcRequest = z.infer<typeof rpcRequestSchema>;

export type RpcResponse =
  | {
      result: string;
      error?: undefined;
    }
  | {
      error: { message: string; code?: unknown; stack?: string };
    };

export function createRpcHandler(definition: MethodResolvers): express.RequestHandler {
  const router = express.Router();
  router.post(
    '/',
    express.json(),
    asyncHandler(async (req, res) => {
      const parseResult = rpcRequestSchema.safeParse(req.body);
      if (!parseResult.success) {
        res.status(400).send(fromZodError(parseResult.error));
        return;
      }

      const { name, params } = parseResult.data;

      if (!hasOwnProperty(definition, name)) {
        // This is important to avoid RCE
        res.status(404).end();
        return;
      }
      const method: MethodResolver<any> = definition[name];

      let rawResult;
      let error: Error | null = null;
      try {
        const ctx = await createServerContext(req, res);
        rawResult = await withContext(ctx, async () => {
          return method({ params, req, res });
        });
      } catch (rawError) {
        error = errorFrom(rawError);
      }

      const responseData: RpcResponse = error
        ? { error: serializeError(error) }
        : { result: superjson.stringify(rawResult) };

      res.json(responseData);
    }),
  );
  return router;
}

export function createMethod<F extends Method>(handler: MethodResolver<F>): MethodResolver<F> {
  return handler;
}
